Form.ModuleCode:
&НаСервере
Процедура ВыполнитьВыдачуНаСервере(Команда)
    Попытка
        СсылкаВыдачи = УправлениеВыдачами.ВыдатьКнигу(Книга, Читатель, ПлановаяДатаВозврата);
        Сообщить("Выдача оформлена: " + СсылкаВыдачи);
        ОчиститьПоля();
        ОбновитьСписки();
    Исключение
        Сообщить("Ошибка: " + ОписаниеОшибки());
    КонецПопытки;
КонецПроцедуры

&НаСервере
Процедура ВыполнитьВозвратНаСервере(Команда)
    Попытка
        // Ищем активную выдачу по книге
        Запрос = Новый Запрос(
            "ВЫБРАТЬ В.Ссылка КАК Выдача ИЗ Документ.ВыдачаКниги КАК В
            |ГДЕ В.Проведен И В.Книга = &Книга
            |   И НЕ В.Ссылка В (ВЫБРАТЬ Возврат.ДокументВыдачи ИЗ Документ.ВозвратКниги КАК Возврат ГДЕ Возврат.Проведен)");
        Запрос.УстановитьПараметр("Книга", КнигаДляВозврата);
        Выборка = Запрос.Выполнить().Выбрать();
        Если НЕ Выборка.Следующий() Тогда
            Сообщить("По этой книге нет активной выдачи");
            Возврат;
        КонецЕсли;
        УправлениеВыдачами.ВернутьКнигу(Выборка.Выдача, ТекущаяДата());
        Сообщить("Возврат оформлен");
        ОбновитьСписки();
    Исключение
        Сообщить("Ошибка: " + ОписаниеОшибки());
    КонецПопытки;
КонецПроцедуры

&НаСервере
Процедура ЭкспортироватьПросрочки(Команда)
    ПутьКФайлу = КаталогВременныхФайлов() + "overdue_" +
        Формат(ТекущаяДата(), "ДФ=yyyyMMdd_HHmmss") + ".csv";
    Рез = ЭкспортПросрочек.ЭкспортироватьВCSV(ПутьКФайлу);
    Сообщить("Экспортировано: " + Рез.ЗаписейЭкспортировано + " в " + ПутьКФайлу);
КонецПроцедуры

&НаСервере
Процедура ОбновитьСписки()
    АктивныеВыдачи = РаботаСКнигами.ПолучитьСписокКниг(Новый Структура("ТолькоВыданные", Истина));
    Просрочки = УправлениеВыдачами.ПолучитьОтчетПросрочки();
КонецПроцедуры

&НаСервере
Процедура ОчиститьПоля()
    Книга = Неопределено;
    Читатель = Неопределено;
    ПлановаяДатаВозврата = Дата(1,1,1);
КонецПроцедуры
